sql:
SELECT category_id, COUNT(app_id) AS number_of_applications
FROM applications
GROUP BY category_id;

SELECT app_id, COUNT(run_id) AS total_runs, AVG(run_id) AS avg_run_id
FROM runs
GROUP BY app_id;

SELECT a.app_name, c.category_name
FROM applications a
JOIN categories c ON a.category_id = c.category_id;

SELECT category_name, description, COUNT(*) AS category_count
FROM categories
GROUP BY category_name, description;

SELECT run_name
FROM runs
WHERE status = 'completed';

SELECT access_id, access_date, access_type, user_id
FROM access_logs
ORDER BY access_date DESC;

SELECT AVG(strftime('%s', end_time) - strftime('%s', start_time)) AS average_duration_seconds
FROM runs
WHERE environment = 'production' AND status = 'completed';

external_knowledge:
- "gardeners" refers to the users;
- "sown more than one seed of summary knowledge" refers to creating more than one summary report;
- "within the fertile ground of September and early October 2023" refers to the creation dates between '2023-09-01' and '2023-10-01'.

sql:
SELECT version_number, version_description
FROM version_history
WHERE version_number = 1;

external_knowledge:
- 'Tech team members' refers to users with roles 'developer' or 'data scientist';
- 'Highly active' means users who have submitted more than two reports;
- 'Typical version' refers to the average version number used by these users;
- 'Between September and early October last year' refers to the period from September 1, 2023, to October 1, 2023.
